     1→import { useCallback } from 'react';
     2→import { getClientNRC } from '../../hooks/useSelectors';
     3→import { invoiceCashbackPermissionService } from '../services';
     4→import { useRootStore } from '~/store';
     5→
     6→export function useInvoiceCashbackPermission() {
     7→  const accountId = getClientNRC();
     8→
     9→  const { hasRedeemed, isLoading, isError } = useRootStore(
    10→    (state) => state.invoiceCashbackPermission
    11→  );
    12→
    13→  const { setHasRedeemed, setLoading, setError } = useRootStore(
    14→    (state) => state.invoiceCashbackPermissionActions
    15→  );
    16→
    17→  const checkHasRedeemed = useCallback(
    18→    async ({
    19→      showLoading = false,
    20→      forceRefresh = false,
    21→    }: { showLoading?: boolean; forceRefresh?: boolean } = {}): Promise<boolean> => {
    22→      if (hasRedeemed !== null && !forceRefresh) {
    23→        return hasRedeemed;
    24→      }
    25→
    26→      if (!accountId) {
    27→        throw new Error('Expected accountId to be defined.');
    28→      }
    29→
    30→      if (showLoading) {
    31→        setLoading(true);
    32→      }
    33→
    34→      try {
    35→        const result = await invoiceCashbackPermissionService.hasRedeemed(accountId);
    36→        setHasRedeemed(result);
    37→        return result;
    38→      } catch {
    39→        setError(true);
    40→        return false;
    41→      }
    42→    },
    43→    [accountId, hasRedeemed, setHasRedeemed, setLoading, setError]
    44→  );
    45→
    46→  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    47→    if (!accountId) {
    48→      return false;
    49→    }
    50→
    51→    try {
    52→      await invoiceCashbackPermissionService.markAsRedeemed(accountId);
