import type { StateCreator } from 'zustand';
import type { InvoiceCashbackPermissionActions, InvoiceCashbackPermissionState } from '../models';

export type InvoiceCashbackPermissionSlice = {
  invoiceCashbackPermission: InvoiceCashbackPermissionState;
  invoiceCashbackPermissionActions: InvoiceCashbackPermissionActions;
};

const initialState: InvoiceCashbackPermissionState = {
  hasRedeemed: null,
  isLoading: false,
  isError: false,
};

export const createInvoiceCashbackPermissionSlice: StateCreator<
  InvoiceCashbackPermissionSlice,
  [],
  [],
  InvoiceCashbackPermissionSlice
> = (set) => ({
  invoiceCashbackPermission: initialState,
  invoiceCashbackPermissionActions: {
    setHasRedeemed: (value: boolean) =>
      set((state: InvoiceCashbackPermissionSlice) => ({
        invoiceCashbackPermission: {
          ...state.invoiceCashbackPermission,
          hasRedeemed: value,
          isLoading: false,
          isError: false,
        },
      })),
    setLoading: (isLoading: boolean) =>
      set((state: InvoiceCashbackPermissionSlice) => ({
        invoiceCashbackPermission: {
          ...state.invoiceCashbackPermission,
          isLoading,
          ...(isLoading && { isError: false }),
        },
      })),
    setError: (isError: boolean) =>
      set((state: InvoiceCashbackPermissionSlice) => ({
        invoiceCashbackPermission: {
          ...state.invoiceCashbackPermission,
          isLoading: false,
          isError,
        },
      })),
    reset: () =>
      set({
        invoiceCashbackPermission: initialState,
      }),
  },
});

